"use client"
import React, { createContext, useContext, useState, useMemo } from 'react';

export const regions = [
  { id: 'mx', name: 'México', flag: '🇲🇽', currency: 'MXN', rate: 1 },
  { id: 'us', name: 'USA', flag: '🇺🇸', currency: 'USD', rate: 0.054 }, 
  { id: 'eu', name: 'Europa', flag: '🇪🇺', currency: 'EUR', rate: 0.050 },
];

const CurrencyContext = createContext<any>(null);

export function CurrencyProvider({ children }: { children: React.ReactNode }) {
  const [region, setRegion] = useState('mx');

  // Buscamos la región actual basándonos en el ID del estado
  const currentRegion = useMemo(() => 
    regions.find(r => r.id === region) || regions[0]
  , [region]);

  const formatPrice = (priceInMxn: any) => {
    const basePrice = Number(priceInMxn) || 0;
    // Multiplicamos por la tasa de la región actual
    const converted = basePrice * currentRegion.rate;
    
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: currentRegion.currency,
    }).format(converted);
  };

  return (
    <CurrencyContext.Provider value={{ region, setRegion, formatPrice, currency: currentRegion.currency }}>
      {children}
    </CurrencyContext.Provider>
  );
}

export const useCurrency = () => {
  const context = useContext(CurrencyContext);
  if (!context) throw new Error("useCurrency debe usarse dentro de CurrencyProvider");
  return context;
};